	//  style={{ color: "white" }}

	// {viewBanner == 1 && <a href="https://vk.com/app51748467#utm_campaign=promo&utm_source=fotoz" target="_blank"><img src={imgOb} style={{ display: "block", margin: "0 auto", width: "95%" }} onClick={() => axios.get(site + "event?type=ob&" + getParams)} /></a> }

	let countViewBlocksValues = countViewBlocks;

	let scrollCategoryInfo = scrollCategories;
	let maxValuesScroll = maxScroll;
	let countSendImages = countSaveSentImages;

	function startTrackingScroll (scrollCategory, listImages = listIdsImages, user_info = fetchedUser) {
		window.scrollTo(0, scrollCategories[scrollCategory - 1]);
		if(user_info.sex == 1) {

			let scrollTopNumber = 0;
			let timeScroll = 0;
			let maxUpdate = 0;
			intervalScroll.current = setInterval(() => {
				timeScroll += 1;
				//scrollTopNumber = document.querySelector("#root").scrollTop;
				scrollTopNumber = pageYOffset;
				//console.log(scrollTopNumber);
				if(scrollTopNumber > maxValuesScroll[scrollCategory-1]) {
		      		maxValuesScroll[scrollCategory-1] = scrollTopNumber;
		      		//console.log('update!');
		    		maxUpdate = 1;
		      	}

		      	if(maxUpdate == 1 && timeScroll >= 5) {
		      		maxUpdate = 0;
		      		let countImages = Math.floor((maxValuesScroll[scrollCategory-1] + window.innerHeight - 50) / 250) * (platform === Platform.VKCOM ? 4 : 2);
	      			let sendImages = [];
	      			let newViews = 0;
	      			while(countImages > countSendImages[scrollCategory-1]) {
	      				sendImages.push(listImages[scrollCategory-1][countSendImages[scrollCategory-1]]);
	      				countSendImages[scrollCategory-1] += 1;
	      				newViews = 1;
	      			}
	      			if(newViews == 1) {
		      			//console.log('send '+scrollCategory+'; '+countSendImages[scrollCategory-1]+'; '+countImages+': '+sendImages.join(','));
		      			let viewsData = new FormData();
		      			viewsData.append('images', sendImages.join(','));
		      			viewsData.append('category', scrollCategory);

		      			axios({
							method: "post",
							url: site + "views?" + getParams,
							data: viewsData
						});
		      			timeScroll = 0;
		      		}
		      	}
		    }, 1000);
		}
	}

	function stopTrackingScroll () {
		if(fetchedUser.sex == 1) {
			clearInterval(intervalScroll.current);
			let scrollTopNumber = maxScroll[activeTabCategory - 1];
			let countImages = Math.floor((scrollTopNumber + window.innerHeight - 50) / 250) * (platform === Platform.VKCOM ? 4 : 2);
			let sendImages = [];

			if(countImages > countSendImages[activeTabCategory - 1]) {
				while(countImages > countSendImages[activeTabCategory - 1]) {
					sendImages.push(listIdsImages[activeTabCategory - 1][countSendImages[activeTabCategory - 1]]);
					countSendImages[activeTabCategory - 1] += 1;
				}
				//console.log('save '+countImages+': '+sendImages.join(','));
				let viewsData = new FormData();
				viewsData.append('images', sendImages.join(','));
				viewsData.append('category', activeTabCategory);

				axios({
					method: "post",
					url: site + "views?" + getParams,
					data: viewsData
				});
			}

			setCountSaveSentImages(countSendImages);
			setMaxScroll(maxValuesScroll);
		}
	}

