		})
		.then((data) => { 
		    if (data.result) { 
		      	if(fromPage == 1) {
		      		setJoinGroup(0);
		      		actionAfterGroup(1);
		      	} else {
		      		axios.get(site + "event?type=join_1&" + getParams);
		      		setChangeImgOpen(1);
		      	}
